#include <Wire.h>
#include <VL53L0X.h>
#include <OneWire.h>
#include <DallasTemperature.h>
#include <AccelStepper.h>
#include <SD.h>
#define STEP_PIN 3
#define DIR_PIN 4
#define SD_CS 10
#define ONE_WIRE_BUS 2
#define BUZZER 8
#define LED 9
#define N_POINTS 10
#define STEPS_SPAN 200
#define ACI_LIM 0.33f
VL53L0X tof;
OneWire ow(ONE_WIRE_BUS); DallasTemperature ds(&ow);
AccelStepper stepper(AccelStepper::DRIVER,STEP_PIN,DIR_PIN);
int ref_mm=50;
float prev_widths[N_POINTS]={0};
unsigned long prev_time=0;

float tof_crack_width_mm(int t,int r){float d=(float)(t-r);return d<0?0:d;}

float thermal_correct(float w,float T){return w-0.010f*(T-20.0f);}

void scan_beam(float*widths){
  for(int i=0;i<N_POINTS;i++){
    stepper.moveTo(i*(STEPS_SPAN/N_POINTS));stepper.runToPosition();
    int d=tof.readRangeSingleMillimeters();
    widths[i]=tof_crack_width_mm(d,ref_mm);
  }
  stepper.moveTo(0);stepper.runToPosition();
}

void run_alarm(float*w,float*pw,float dt_days){
  bool fault=false;
  for(int i=0;i<N_POINTS;i++){
    if(w[i]>ACI_LIM) fault=true;
    if(dt_days>0&&(w[i]-pw[i])/dt_days>0.05f) fault=true;
  }
  if(fault){tone(BUZZER,1500);analogWrite(LED,255);}else{noTone(BUZZER);analogWrite(LED,0);}
}

void log_sd(float*w,float T){
  File f=SD.open("crack.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.print(T);
    for(int i=0;i<N_POINTS;i++){f.print(',');f.print(w[i]);}f.println();f.close();}
}

void setup(){Wire.begin();tof.init();tof.setTimeout(500);ds.begin();SD.begin(SD_CS);stepper.setMaxSpeed(400);stepper.setAcceleration(200);Serial.begin(115200);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);}

void loop(){
  float widths[N_POINTS];
  ds.requestTemperatures();float T=ds.getTempCByIndex(0);
  scan_beam(widths);
  for(int i=0;i<N_POINTS;i++) widths[i]=thermal_correct(widths[i],T);
  float dt_days=(millis()-prev_time)/86400000.0f;
  run_alarm(widths,prev_widths,dt_days);
  log_sd(widths,T);
  for(int i=0;i<N_POINTS;i++) prev_widths[i]=widths[i];
  prev_time=millis();
  delay(3600000);
}
